import React, { useState } from "react";
import {
  Menu,
  X,
  Leaf,
  Award,
  Cpu,
  Heart,
  Star,
  ArrowLeft,
  Cookie,
  CheckCircle2,
  Facebook,
  Instagram,
  Phone,
  Mail,
  MapPin,
  ChevronLeft,
} from "lucide-react";

/* =======================
   Constants
======================= */

const COMPANY_INFO = {
  founded: "2023",
  name: "بيسكوزا",
  tagline: "لحظات من السعادة",
  story_title: "حكاية تأسيس بيسكوزا",
  story_text_1:
    "شركة سورية متخصصة في صناعة البسكويت تأسست عام 2023 بشغف كبير لتقديم منتجات عالية الجودة.",
  story_text_2: "نحرص على استخدام أجود المكونات لإنتاج أصناف ذات جودة عالية.",
  quality_text:
    "التزامنا بالجودة والتميز والمعايير العالمية لتحقيق رضا زبائننا.",
  mission:
    "في بيسكوزا نؤمن أن قطعة من البسكويت قد تكون سبباً لسعادة تشعر بها خلال يومك",
};

const NAV_LINKS = [
  { label: "الرئيسية", href: "#" },
  { label: "من نحن", href: "#" },
  { label: "منتجاتنا", href: "#" },
  { label: "تواصل معنا", href: "#" },
];

const FEATURES = [
  {
    title: "أجود المكونات",
    description: "مكونات طبيعية مختارة بعناية.",
    icon: <Leaf />,
  },
  {
    title: "تكنولوجيا متطورة",
    description: "خطوط إنتاج مؤتمتة بالكامل.",
    icon: <Cpu />,
  },
  {
    title: "جودة عالمية",
    description: "نلتزم بأعلى المعايير.",
    icon: <Award />,
  },
  {
    title: "شغفنا السعادة",
    description: "نصنع لحظات فرح.",
    icon: <Heart />,
  },
];

/* =======================
   Components
======================= */

function IdentityShape({ className = "", color = "#c2ddd5" }) {
  return (
    <svg viewBox="0 0 100 100" className={className} preserveAspectRatio="none">
      <circle cx="50" cy="50" r="40" fill={color} fillOpacity="0.2" />
    </svg>
  );
}

function Navbar() {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <nav className="navbar">
      <button onClick={() => setIsOpen(!isOpen)}>
        {isOpen ? <X /> : <Menu />}
      </button>

      {isOpen && (
        <div>
          {NAV_LINKS.map((link) => (
            <a key={link.label} href={link.href}>
              {link.label}
            </a>
          ))}
        </div>
      )}
    </nav>
  );
}

function Hero() {
  return (
    <section className="hero">
      <h1>عالم السعادة</h1>
      <p>منذ {COMPANY_INFO.founded}</p>
      <button>
        تذوق منتجاتنا <ArrowLeft />
      </button>
    </section>
  );
}

function StorySection() {
  return (
    <section>
      <h2>{COMPANY_INFO.story_title}</h2>
      <p>{COMPANY_INFO.story_text_1}</p>
      <p>{COMPANY_INFO.story_text_2}</p>
    </section>
  );
}

function QualitySection() {
  return (
    <section>
      <h2>الجودة والتميز</h2>
      <div>
        {FEATURES.map((feature, i) => (
          <div key={i}>
            {feature.icon}
            <h3>{feature.title}</h3>
            <p>{feature.description}</p>
          </div>
        ))}
      </div>
    </section>
  );
}

function Footer() {
  return (
    <footer>
      <p>{COMPANY_INFO.mission}</p>
      <Facebook />
      <Instagram />
    </footer>
  );
}

/* =======================
   Main Component
======================= */

export default function AboutUs() {
  return (
    <div dir="rtl">
      <Navbar />
      <Hero />
      <StorySection />
      <QualitySection />
      <Footer />
    </div>
  );
}
